fn max_distance_squared(
    (x1, y1): (f64, f64),
    (x2, y2): (f64, f64),
    (x3, y3): (f64, f64),
    z1: f64,
    z2: f64,
    z3: f64,
) -> f64 {
    let d12_sq = (x1 - x2).powi(2) + (y1 - y2).powi(2) + (z1 - z2).powi(2);
    let d23_sq = (x2 - x3).powi(2) + (y2 - y3).powi(2) + (z2 - z3).powi(2);
    let d31_sq = (x3 - x1).powi(2) + (y3 - y1).powi(2) + (z3 - z1).powi(2);
    d12_sq.max(d23_sq).max(d31_sq)
}
